package com.tp1jdbc;

import com.tp1jdbc.entities.ProductoDTO;
import com.tp1jdbc.factory.AbstractFactory;
import com.tp1jdbc.utils.DataLoader;

import java.sql.SQLException;

public class Main {

    public static void main(String[] args) throws SQLException {

        AbstractFactory mysqlFactory  = AbstractFactory.getDAOFactory(AbstractFactory.MYSQL_JDBC);
        AbstractFactory mariaDBFactory  = AbstractFactory.getDAOFactory(AbstractFactory.MARIA_DB_JDBC);

        poblarDB(mysqlFactory);
        poblarDB(mariaDBFactory);
        //Borrar o eliminar luego de que se haya pobaldo ambas DB.

        // 3. Producto que mas recaudo
        ProductoDTO pDTO = mysqlFactory.getProductoDAO().obtenerProductoQueMasRecaudoDTO();
        System.out.println("Producto que mas recaudo: " + pDTO);

        // 4. Clientes que mas facturaron (Top 5)
        mysqlFactory.getClienteDAO().obtenerTop5ClientesPorFacturacion();
    }

    /**
     * Carga los datos desde los CSVs en la base de datos indicada por la factory.
     *
     * @param factory factory que provee la conexión y los DAOs de la BD destino
     */
    private static void poblarDB(AbstractFactory factory) {
        DataLoader.inicializarMetadata(factory);
        factory.closeConnection();
    }
}

package com.tp1jdbc;

import com.tp1jdbc.entities.ProductoDTO;
import com.tp1jdbc.factory.AbstractFactory;
import com.tp1jdbc.utils.DataLoader;

import java.sql.SQLException;

/**
 * Punto de entrada de la aplicación. Ejecuta las consultas principales contra la base de datos MySQL.
 *
 * @version 1.0
 */
public class Main {

    /** Constructor privado. Esta clase no debe instanciarse. */
    private Main() {}

    /**
     * Método principal de la aplicación.
     *
     * @param args argumentos de línea de comandos (no utilizados)
     * @throws SQLException si ocurre un error en la conexión a la base de datos
     */
    public static void main(String[] args) throws SQLException {

        AbstractFactory mysqlFactory  = AbstractFactory.getDAOFactory(AbstractFactory.MYSQL_JDBC);
        AbstractFactory mariaDBFactory  = AbstractFactory.getDAOFactory(AbstractFactory.MARIA_DB_JDBC);

        poblarDB(mysqlFactory);
        poblarDB(mariaDBFactory);
        //Borrar o eliminar luego de que se haya pobaldo ambas DB.

        // 3. Producto que mas recaudo
        ProductoDTO pDTO = mysqlFactory.getProductoDAO().obtenerProductoQueMasRecaudoDTO();
        System.out.println("Producto que mas recaudo: " + pDTO);

        // 4. Clientes que mas facturaron (Top 5)
        mysqlFactory.getClienteDAO().obtenerTop5ClientesPorFacturacion();
    }

    /**
     * Carga los datos desde los CSVs en la base de datos indicada por la factory.
     *
     * @param factory factory que provee la conexión y los DAOs de la BD destino
     */
    private static void poblarDB(AbstractFactory factory) {
        DataLoader.inicializarMetadata(factory);
        factory.closeConnection();
    }
}

package com.tp1jdbc.factory;

import com.tp1jdbc.dao.impl.ClienteDAO;
import com.tp1jdbc.dao.impl.FacturaDAO;
import com.tp1jdbc.dao.impl.FacturaProductoDAO;
import com.tp1jdbc.dao.impl.ProductoDAO;

import java.lang.reflect.InvocationTargetException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;

/**
 * Implementación concreta de {@link AbstractFactory} para MariaDB.
 * Gestiona la conexión como singleton para ser reutilizada por todos los DAOs.
 *
 * @version 1.0
 */
public class MariaDbDaoFactory extends AbstractFactory {

    private static MariaDbDaoFactory instance;

    public static final String DRIVER = "org.mariadb.jdbc.Driver";
    public static final String uri = "jdbc:mariadb://localhost:3307/integrador1_db";
    public static Connection conn;

    private MariaDbDaoFactory() {
    }

    /**
     * Devuelve la instancia singleton de esta fábrica.
     *
     * @return instancia única de {@code MariaDbDaoFactory}
     */
    public static synchronized MariaDbDaoFactory getInstance() {
        if (instance == null) {
            instance = new MariaDbDaoFactory();
        }
        return instance;
    }

    /**
     * Crea y retorna la conexión a MariaDB, reutilizándola si ya existe.
     *
     * @return conexión JDBC activa
     */
    public static Connection createConnection() {
        if (conn != null) {
            return conn;
        }
        try {
            Class.forName(DRIVER).getDeclaredConstructor().newInstance();
        } catch (InstantiationException | IllegalAccessException | IllegalArgumentException | InvocationTargetException
                 | NoSuchMethodException | SecurityException | ClassNotFoundException e) {
            e.printStackTrace();
            System.exit(1);
        }

        try {
            conn = DriverManager.getConnection(uri, "root", "");
            conn.setAutoCommit(false);
        } catch (SQLException e) {
            e.printStackTrace();
        }
        return conn;
    }

    /**
     * Cierra la conexión activa con MariaDB.
     */
    public void closeConnection() {
        try {
            conn.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.Cliente} para MariaDB.
     *
     * @return instancia de {@link ClienteDAO}
     */
    @Override
    public ClienteDAO getClienteDAO() {
        return new ClienteDAO(createConnection());
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.Factura} para MariaDB.
     *
     * @return instancia de {@link FacturaDAO}
     */
    @Override
    public FacturaDAO getFacturaDAO() {
        return new FacturaDAO(createConnection());
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.Producto} para MariaDB.
     *
     * @return instancia de {@link ProductoDAO}
     */
    @Override
    public ProductoDAO getProductoDAO() {
        return new ProductoDAO(createConnection());
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.FacturaProducto} para MariaDB.
     *
     * @return instancia de {@link FacturaProductoDAO}
     */
    @Override
    public FacturaProductoDAO getFacturaProductoDAO() {
        return new FacturaProductoDAO(createConnection());
    }
}

package com.tp1jdbc.factory;

import com.tp1jdbc.dao.impl.ClienteDAO;
import com.tp1jdbc.dao.impl.FacturaDAO;
import com.tp1jdbc.dao.impl.FacturaProductoDAO;
import com.tp1jdbc.dao.impl.ProductoDAO;

import java.lang.reflect.InvocationTargetException;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;

/**
 * Implementación concreta de {@link AbstractFactory} para MariaDB.
 * Gestiona la conexión como singleton para ser reutilizada por todos los DAOs.
 *
 * @version 1.0
 */
public class MariaDbDaoFactory extends AbstractFactory {

    private static MariaDbDaoFactory instance;

    /** Nombre completo del driver JDBC de MariaDB. */
    public static final String DRIVER = "org.mariadb.jdbc.Driver";

    /** URL de conexión JDBC a la base de datos MariaDB. */
    public static final String uri = "jdbc:mariadb://localhost:3307/integrador1_db";

    /** Conexión JDBC compartida (singleton). */
    public static Connection conn;

    private MariaDbDaoFactory() {
    }

    /**
     * Devuelve la instancia singleton de esta fábrica.
     *
     * @return instancia única de {@code MariaDbDaoFactory}
     */
    public static synchronized MariaDbDaoFactory getInstance() {
        if (instance == null) {
            instance = new MariaDbDaoFactory();
        }
        return instance;
    }

    /**
     * Crea y retorna la conexión a MariaDB, reutilizándola si ya existe.
     *
     * @return conexión JDBC activa
     */
    public static Connection createConnection() {
        if (conn != null) {
            return conn;
        }
        try {
            Class.forName(DRIVER).getDeclaredConstructor().newInstance();
        } catch (InstantiationException | IllegalAccessException | IllegalArgumentException | InvocationTargetException
                 | NoSuchMethodException | SecurityException | ClassNotFoundException e) {
            e.printStackTrace();
            System.exit(1);
        }

        try {
            conn = DriverManager.getConnection(uri, "root", "");
            conn.setAutoCommit(false);
        } catch (SQLException e) {
            e.printStackTrace();
        }
        return conn;
    }

    /**
     * Cierra la conexión activa con MariaDB.
     */
    public void closeConnection() {
        try {
            conn.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.Cliente} para MariaDB.
     *
     * @return instancia de {@link ClienteDAO}
     */
    @Override
    public ClienteDAO getClienteDAO() {
        return new ClienteDAO(createConnection());
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.Factura} para MariaDB.
     *
     * @return instancia de {@link FacturaDAO}
     */
    @Override
    public FacturaDAO getFacturaDAO() {
        return new FacturaDAO(createConnection());
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.Producto} para MariaDB.
     *
     * @return instancia de {@link ProductoDAO}
     */
    @Override
    public ProductoDAO getProductoDAO() {
        return new ProductoDAO(createConnection());
    }

    /**
     * Obtiene el DAO de {@link com.tp1jdbc.entities.FacturaProducto} para MariaDB.
     *
     * @return instancia de {@link FacturaProductoDAO}
     */
    @Override
    public FacturaProductoDAO getFacturaProductoDAO() {
        return new FacturaProductoDAO(createConnection());
    }
}
